sql:
SELECT station_name, status
FROM monitoring_stations
ORDER BY station_name;

SELECT station_id, MAX(date) AS last_maintenance_date
FROM maintenances
GROUP BY station_id;

SELECT COUNT(*) AS maintenance_count
FROM maintenances
WHERE technician_id = 0;

